import { useEffect, useState } from "react";
import API from "../../api/axios";
import {
  Box,
  Card,
  CardContent,
  Typography,
  TextField,
  MenuItem,
  Button,
  Table,
  TableHead,
  TableRow,
  TableCell,
  TableBody,
} from "@mui/material";

export default function OrganizationList() {
  const [orgs, setOrgs] = useState([]);
  const [users, setUsers] = useState([]);

  const [selectedOrg, setSelectedOrg] = useState("");
  const [selectedUser, setSelectedUser] = useState("");

  // 🔥 fetch orgs
  const fetchOrgs = async () => {
    const res = await API.get("organizations/");
    setOrgs(res.data);
  };

  // 🔥 fetch users
  const fetchUsers = async (orgId) => {
    const res = await API.get(`users-by-org/${orgId}/`);
    setUsers(res.data);
  };

  useEffect(() => {
    fetchOrgs();
  }, []);

  // 🔥 ADD USER (assign user to org)
  const addUser = async () => {
    await API.post("assign-user/", {
      username: selectedUser,
      organization_id: selectedOrg,
    });
    alert("User Added ✅");
    fetchUsers(selectedOrg);
  };

  return (
    <Box
      sx={{
        height: "100vh",
        display: "flex",
        justifyContent: "center",
        alignItems: "center",
        background: "linear-gradient(135deg, #1e3c72, #2a5298)",
      }}
    >
      <Card sx={{ width: 500, borderRadius: 4, p: 2 }}>
        <CardContent>
          <Typography variant="h5" mb={2}>
            Organization List
          </Typography>

          {/* ORG SELECT */}
          <TextField
            select
            fullWidth
            label="Organization Name"
            margin="normal"
            onChange={(e) => {
              setSelectedOrg(e.target.value);
              fetchUsers(e.target.value);
            }}
          >
            {orgs.map((o) => (
              <MenuItem key={o.id} value={o.id}>
                {o.name}
              </MenuItem>
            ))}
          </TextField>

          {/* USER DROPDOWN */}
          <TextField
            select
            fullWidth
            label="Add User"
            margin="normal"
            onChange={(e) => setSelectedUser(e.target.value)}
          >
            {users.map((u) => (
              <MenuItem key={u.id} value={u.username}>
                {u.username}
              </MenuItem>
            ))}
          </TextField>

          <Button fullWidth variant="contained" onClick={addUser}>
            ADD USER
          </Button>

          {/* 🔥 TABLE */}
          <Typography mt={3}>User List</Typography>

          <Table>
            <TableHead>
              <TableRow>
                <TableCell>Username</TableCell>
                <TableCell>Role</TableCell>
              </TableRow>
            </TableHead>

            <TableBody>
              {users.map((u) => (
                <TableRow key={u.id}>
                  <TableCell>{u.username}</TableCell>
                  <TableCell>{u.role}</TableCell>
                </TableRow>
              ))}
            </TableBody>
          </Table>
        </CardContent>
      </Card>
    </Box>
  );
}
